/**
 * @name TaskInstance.getLogPath flows to file read - path stored in DB but not validated
 * @description The log path retrieved from TaskInstance (via DB) flows to file read operations without canonicalization
 * @kind path-problem
 * @problem.severity error
 * @id java/taskinstance-logpath-to-file
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module TaskLogPathConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Source: getLogPath() call on a TaskInstance object
    exists(MethodCall mc |
      mc.getMethod().hasName("getLogPath") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Sink: File constructor or file reading methods
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    exists(MethodCall mc |
      (
        mc.getMethod().hasName("rollViewLogLines") or
        mc.getMethod().hasName("readPartFileContent") or
        mc.getMethod().hasName("getLogBytes") or
        mc.getMethod().hasName("queryLog")
      ) and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module TaskLogPathFlow = TaintTracking::Global<TaskLogPathConfig>;
import TaskLogPathFlow::PathGraph

from TaskLogPathFlow::PathNode source, TaskLogPathFlow::PathNode sink
where TaskLogPathFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "TaskInstance.getLogPath() flows to file operation from $@. Path not canonicalized.", source.getNode(), "getLogPath()"

/**
 * @name LoggerRequestProcessor: path from deserialized RollViewLogRequest with no path prefix check
 * @description Network-supplied log path in RollViewLogRequestCommand flows to file reading with no containment validation
 * @kind path-problem
 * @problem.severity error
 * @id java/logger-request-processor-roll-view-path
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module RollViewLogConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Source: getPath() or similar on deserialized command objects in LoggerRequestProcessor
    exists(MethodCall mc |
      (
        mc.getMethod().hasName("getPath") or
        mc.getMethod().hasName("getLogPath") or
        mc.getMethod().hasName("getFilePath")
      ) and
      mc.getEnclosingCallable().getDeclaringType().hasName("LoggerRequestProcessor") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      (
        mc.getMethod().hasName("readPartFileContent") or
        mc.getMethod().hasName("rollViewLogLines") or
        mc.getMethod().hasName("getLogBytes")
      ) and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
  }
}

module RollViewLogFlow = TaintTracking::Global<RollViewLogConfig>;
import RollViewLogFlow::PathGraph

from RollViewLogFlow::PathNode source, RollViewLogFlow::PathNode sink
where RollViewLogFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Network-supplied log path from $@ flows to file read with no validation.", source.getNode(), "deserialized command path"
